```typescript
describe("DCG Statistics Service", () => {
  beforeAll(async () => {
    // Seed test data
    await seedDCGTestData();
    logger.info({ testName: "beforeAll" }, "Seeded DCG test data");
  });

  describe("getOverviewStats", () => {
    it("should return accurate counts", async () => {
      const stats = await getStats();

      expect(stats.overview.totalBlocks).toBeGreaterThan(0);
      expect(stats.overview.blocksLast24h).toBeLessThanOrEqual(stats.overview.totalBlocks);
      expect(stats.overview.falsePositiveRate).toBeGreaterThanOrEqual(0);
      expect(stats.overview.falsePositiveRate).toBeLessThanOrEqual(1);

      logger.info({
        testName: "overview_stats",
        overview: stats.overview,
        correlationId: getCorrelationId(),
      }, "Overview stats accurate");
    });

    it("should calculate trends correctly", async () => {
      const stats = await getStats();

      expect(typeof stats.overview.trendVsYesterday).toBe("number");
      expect(typeof stats.overview.trendVsLastWeek).toBe("number");

      logger.info({
        testName: "trend_calculation",
        trendVsYesterday: stats.overview.trendVsYesterday,
        trendVsLastWeek: stats.overview.trendVsLastWeek,
        correlationId: getCorrelationId(),
      }, "Trends calculated");
    });
  });

  describe("getSeverityDistribution", () => {
    it("should return all severity levels", async () => {
      const stats = await getStats();

      expect(stats.severityDistribution).toHaveProperty("critical");
      expect(stats.severityDistribution).toHaveProperty("high");
      expect(stats.severityDistribution).toHaveProperty("medium");
      expect(stats.severityDistribution).toHaveProperty("low");

      const total = Object.values(stats.severityDistribution).reduce((a, b) => a + b, 0);
      expect(total).toBe(stats.overview.totalBlocks);

      logger.info({
        testName: "severity_distribution",
        distribution: stats.severityDistribution,
        correlationId: getCorrelationId(),
      }, "Severity distribution accurate");
    });
  });

  describe("getTopRules", () => {
    it("should return rules ordered by block count", async () => {
      const stats = await getStats();

      expect(stats.topRules.length).toBeGreaterThan(0);
      expect(stats.topRules.length).toBeLessThanOrEqual(10);

      // Verify ordering
      for (let i = 1; i < stats.topRules.length; i++) {
        expect(stats.topRules[i - 1].blockCount).toBeGreaterThanOrEqual(stats.topRules[i].blockCount);
      }

      logger.info({
        testName: "top_rules",
        ruleCount: stats.topRules.length,
        topRule: stats.topRules[0],
        correlationId: getCorrelationId(),
      }, "Top rules ordered correctly");
    });

    it("should include false positive count per rule", async () => {
      const stats = await getStats();

      for (const rule of stats.topRules) {
        expect(typeof rule.falsePositiveCount).toBe("number");
        expect(rule.falsePositiveCount).toBeLessThanOrEqual(rule.blockCount);
      }

      logger.info({
        testName: "top_rules_fp_count",
        correlationId: getCorrelationId(),
      }, "False positive counts included");
    });
  });

  describe("getPackStats", () => {
    it("should return stats for each pack with percentage", async () => {
      const stats = await getStats();

      const totalPercentage = stats.packStats.reduce((sum, p) => sum + p.percentage, 0);
      expect(Math.abs(totalPercentage - 100)).toBeLessThan(1); // Allow rounding error

      for (const pack of stats.packStats) {
        expect(pack.topRules.length).toBeLessThanOrEqual(3);
      }

      logger.info({
        testName: "pack_stats",
        packCount: stats.packStats.length,
        totalPercentage,
        correlationId: getCorrelationId(),
      }, "Pack stats with percentages");
    });
  });

  describe("getHourlyTimeSeries", () => {
    it("should return hourly data points", async () => {
      const stats = await getStats();

      expect(Array.isArray(stats.timeSeries.hourly)).toBe(true);

      for (const point of stats.timeSeries.hourly) {
        expect(point.timestamp).toBeInstanceOf(Date);
        expect(typeof point.count).toBe("number");
      }

      logger.info({
        testName: "hourly_timeseries",
        pointCount: stats.timeSeries.hourly.length,
        correlationId: getCorrelationId(),
      }, "Hourly time series valid");
