### Integration Tests (`apps/gateway/tests/integration/dcg-stats.test.ts`)

```typescript
describe("DCG Statistics Integration", () => {
  it("should update stats after new block", async () => {
    const beforeStats = await getQuickStats();

    await ingestBlockEvent({
      command: "test stats command",
      pack: "test.stats",
      ruleId: "test:stats",
      severity: "low",
      reason: "Stats test",
    });

    const afterStats = await getQuickStats();

    expect(afterStats.blocksToday).toBeGreaterThanOrEqual(beforeStats.blocksToday);

    logger.info({
      testName: "stats_after_block",
      beforeBlocksToday: beforeStats.blocksToday,
      afterBlocksToday: afterStats.blocksToday,
      correlationId: getCorrelationId(),
    }, "Stats updated after new block");
  });

  it("should reflect false positive marking in stats", async () => {
    // Create a block
    const block = await ingestBlockEvent({
      command: "test fp command",
      pack: "test.fp",
      ruleId: "test:fp",
      severity: "low",
      reason: "FP test",
    });

    const beforeStats = await getStats();
    const beforeFP = beforeStats.overview.falsePositiveCount;

    // Mark as false positive
    await markFalsePositive(block.id);

    const afterStats = await getStats();
    expect(afterStats.overview.falsePositiveCount).toBe(beforeFP + 1);

    logger.info({
      testName: "fp_reflected_in_stats",
      beforeFP,
      afterFP: afterStats.overview.falsePositiveCount,
      correlationId: getCorrelationId(),
    }, "False positive reflected in stats");
  });
});
